import{_ as l,C as n,o as a,c as s,j as o,E as i,a as r,a3 as g}from"./chunks/framework.DACwFHq9.js";const T=JSON.parse('{"title":"翻译助手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/translation.md","filePath":"user-guide/tools/llm-chat/settings/translation.md","lastUpdated":1778239080000}'),c={name:"user-guide/tools/llm-chat/settings/translation.md"},d={id:"翻译助手",tabindex:"-1"};function u(h,t,m,p,_,f){const e=n("LIcon");return a(),s("div",null,[o("h1",d,[i(e,{name:"Languages",size:"28"}),t[0]||(t[0]=r(" 翻译助手 ",-1)),t[1]||(t[1]=o("a",{class:"header-anchor",href:"#翻译助手","aria-label":'Permalink to "<LIcon name="Languages" size="28" /> 翻译助手"'},"​",-1))]),t[2]||(t[2]=g('<p>翻译助手通过 LLM 赋予了聊天界面跨语言交流的能力。它不仅支持对已接收消息的快速翻译，还能在输入过程中实时转换你的表达。</p><h2 id="核心配置-core-config" tabindex="-1">核心配置 (Core Config) <a class="header-anchor" href="#核心配置-core-config" aria-label="Permalink to &quot;核心配置 (Core Config)&quot;">​</a></h2><ul><li><strong>启用翻译功能</strong>: 总开关。开启后，消息右键菜单及输入框工具栏将激活翻译相关图标。</li><li><strong>翻译模型</strong>: <ul><li><strong>建议</strong>: 选择那些在多语言基准测试中表现优异的模型（如 GPT-4o, Claude 3.5 Sonnet）。</li><li><strong>兜底</strong>: 留空将自动使用全局默认模型。</li></ul></li><li><strong>常用语言列表</strong>: <ul><li>在这里预设你频繁使用的语言（如：简体中文、English、日本語、한국어）。</li><li>这些语言将优先显示在翻译菜单的顶部，方便快速切换。</li></ul></li></ul><h2 id="智能翻译策略" tabindex="-1">智能翻译策略 <a class="header-anchor" href="#智能翻译策略" aria-label="Permalink to &quot;智能翻译策略&quot;">​</a></h2><ul><li><strong>双向目标语言</strong>: <ul><li><strong>消息目标语言</strong>: 设定为你最熟悉的母语，用于快速理解 AI 或他人的回复。</li><li><strong>输入目标语言</strong>: 设定为你正在学习或需要使用的外语。在输入框工具栏点击翻译，系统将自动将你的母语转换为该语言。</li></ul></li><li><strong>翻译提示词 (Prompt)</strong>: <ul><li><strong>高度可定制</strong>: 你可以精细控制翻译的风格（如：信达雅、学术风、口语化）。</li><li><strong>占位符支持</strong>: <ul><li><code>{text}</code>: 待翻译的原文。</li><li><code>{targetLang}</code>: 选中的目标语言。</li><li><code>{thinkTags}</code>: <strong>关键特性</strong>。启用后，系统会保护消息中的思考块（如 <code>&lt;think&gt;...&lt;/think&gt;</code>）不被翻译，仅翻译实际的回复内容，确保逻辑链条的完整。</li></ul></li></ul></li></ul><h2 id="质量控制" tabindex="-1">质量控制 <a class="header-anchor" href="#质量控制" aria-label="Permalink to &quot;质量控制&quot;">​</a></h2><ul><li><strong>温度 (Temperature)</strong>: 默认设为 0.1。较低的温度能确保翻译的忠实度，减少“幻觉”和过度润色。</li><li><strong>Token 限制</strong>: 防止模型在翻译过程中产生不必要的长篇大论。</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>你可以为不同的“智能体 (Agent)”配置不同的翻译提示词。例如，为“英语口语教练”配置更偏向口语化的翻译策略。</p></div>',9))])}const b=l(c,[["render",u]]);export{T as __pageData,b as default};
